import android.util.Log
import timber.log.Timber

class LoggingSystem {
    companion object {
        private const val TAG = "LoggingSystem"

        fun logUserAuthenticationAttempt(successful: Boolean) {
            if (successful) {
                Timber.i("User authentication attempt successful")
            } else {
                Timber.e("User authentication attempt failed")
            }
        }

        fun logDatabaseQuery(query: String, parameters: List<Any>) {
            Timber.d("Database query: $query with parameters: $parameters")
        }

        fun logApiRequest(method: String, url: String, headers: Map<String, String>, body: String) {
            Timber.i("API request: $method to $url with headers: $headers and body: $body")
